package com.grit.liferecorder.ui.navigation
import androidx.compose.foundation.layout.PaddingValues; import androidx.compose.runtime.*; import androidx.navigation.compose.*; import com.grit.liferecorder.AppContainer; import com.grit.liferecorder.ui.calendar.*; import com.grit.liferecorder.ui.components.AppScaffold; import com.grit.liferecorder.ui.habits.*; import com.grit.liferecorder.ui.routines.*; import com.grit.liferecorder.ui.stats.*; import com.grit.liferecorder.ui.tasks.*
@Composable fun AppNavHost(container:AppContainer){ val nav= rememberNavController(); val back by nav.currentBackStackEntryAsState(); val route=back?.destination?.route?:Screen.Calendar.route; AppScaffold(route,{s-> nav.navigate(s.route){ launchSingleTop=true; popUpTo(Screen.Calendar.route) }}){ padding:PaddingValues -> NavHost(navController=nav,startDestination=Screen.Calendar.route){ composable(Screen.Calendar.route){ CalendarScreen(CalendarViewModel(container.calendarRepository,container.journalRepository),padding) }; composable(Screen.Tasks.route){ TasksScreen(TasksViewModel(container.taskRepository),padding) }; composable(Screen.Habits.route){ HabitsScreen(HabitsViewModel(container.habitRepository),padding) }; composable(Screen.Routines.route){ RoutinesScreen(RoutinesViewModel(container.routineRepository),padding) }; composable(Screen.Stats.route){ StatsScreen(StatsViewModel(container.statsRepository),padding) } } } }
